from pydicom.dataset import Dataset
from pydicom.dataelem import DataElement

# Create JSON with BulkDataURI in a sequence manually
json_data = {
    "00209161": {
        "vr": "SQ",
        "Value": [
            {
                "00080018": {
                    "vr": "UI",
                    "Value": ["1.2.3.4.5"]
                },
                "7FE00010": {
                    "vr": "OB",
                    "BulkDataURI": "http://example.com/bulkdata1"
                }
            },
            {
                "00080018": {
                    "vr": "UI", 
                    "Value": ["1.2.3.4.6"]
                },
                "7FE00010": {
                    "vr": "OB",
                    "BulkDataURI": "http://example.com/bulkdata2"
                }
            }
        ]
    }
}

print("JSON with BulkDataURI in sequence:")

# With a handler
print("\nConverting with bulk_data_uri_handler:")
handler_calls = []
def mock_handler(tag, vr, uri):
    handler_calls.append((tag, vr, uri))
    print(f"   Handler called: tag={tag}, vr={vr}, uri={uri}")
    return b'mock_data_for_' + uri.encode()[-1:]

ds_with_handler = Dataset.from_json(json_data, mock_handler)
print(f"   Handler was called {len(handler_calls)} times")
print("   Conversion successful")

# Check the result
print("\nChecking converted dataset:")
if 0x00209161 in ds_with_handler:
    seq = ds_with_handler[0x00209161]
    print(f"   Sequence found with {len(seq.value)} items")
    for i, item in enumerate(seq.value):
        print(f"   Item {i}:")
        for elem in item:
            if isinstance(elem.value, bytes):
                print(f"     {elem.name} ({elem.tag}): VR={elem.VR}, value={elem.value}")
            else:
                print(f"     {elem.name} ({elem.tag}): VR={elem.VR}, value={elem.value}")
EOF

